function* obtenerDatosGraficaLineChart(action) {
  try {
    yield put(manageSpiner({ key: "lineChart", state: true }));
    let rango = obtenerRangoDeFechas(action.value);
    const company = getFromSession("company_id");
    const canales = yield obtenerCanalesPorCompany(company);

    let whatsapp = [];
    let fecha = [];
    let web = [];
    let total = [];
    let ejeY = [];
    let fechaCor = [];
    let arrayCsv = [];
    let horaCor = [];
    let horaCor2 = [];
    let instagram = [];
    let facebook = [];

    let color = "#d35ce6";
    let colorFondo = "#e49cf0";
    let label = "Conversaciones cerradas";

    let payload = {
      dataLabel: label,
      color: color,
      colorBackground: colorFondo,
      graficoGrande: true,
    };
    let resp = yield traerDatosGraficasBigQuery(
      rango,
      "estadisticasGenerales",
      canales
    );

    if (resp) {
      resp.graficoPpal.map((item) => {
        fecha.push(item.fec.value);
      });

      for (var i = 0; i < fecha.length; i++) {
        var split = fecha[i].split("T");
        fechaCor.push(split[0]);
        horaCor.push(split[1]);
      }

      for (var i = 0; i < fecha.length; i++) {
        var split = horaCor[i].split(".");
        horaCor2.push(split[0]);
      }

      if (action.value === "HOY" || action.value === "AYER") {
        payload["ejeX"] = horaCor2;
      } else {
        payload["ejeX"] = fechaCor;
      }

      resp.graficoPpal.map((item) => {
        whatsapp.push(item.whatsapp);
      });
      resp.graficoPpal.map((item) => {
        web.push(item.web);
      });

      resp.graficoPpal.map((item) => {
        total.push(item.total);
      });

      if (canales.includes("facebook")) {
        resp.graficoPpal.map((item) => {
          facebook.push(item.facebook || 0);
        });
      }

      if (canales.includes("instagram")) {
        resp.graficoPpal.map((item) => {
          instagram.push(item.instagram || 0);
        });
      }
    }

    ejeY.push(whatsapp);
    ejeY.push(web);
    ejeY.push(total);
    if (canales.includes("facebook")) {
      ejeY.push(facebook);
    }

    if (canales.includes("instagram")) {
      ejeY.push(instagram);
    }

    resp.graficoPpal.map((item, i) => {
      const fila = {
        fecha: payload["ejeX"][i],
        total: item.total,
        web: item.web,
        whatsapp: item.whatsapp,
      };

      // Solo agrega estos campos si existen en los canales configurados
      if (canales.includes("facebook")) {
        fila.facebook = item.facebook;
      }

      if (canales.includes("instagram")) {
        fila.instagram = item.instagram;
      }

      arrayCsv.push(fila);
    });

    payload["labels"] = ["WhatsApp", "Web", "Total"];

    if (canales.includes("facebook")) {
      payload["labels"].push("Facebook");
    }

    if (canales.includes("instagram")) {
      payload["labels"].push("Instagram");
    }

    payload["ejeY"] = ejeY;
    payload["arrayCsv"] = arrayCsv;

    yield put(
      obtenerDatosGraficaLineChartSuccess({ payload, size: resp.total })
    );
    yield put(manageSpiner({ key: "lineChart", state: false }));
  } catch (error) {
    console.error("saga.obternerDatosGraficaLineChart", error);
  }
}

