async function procesarConvs(convs, idConversacion) {
  let convsCerradas = [];
  // Hace falta ver cuando no encuentra el ID está errado para que no saque error
  if (convs && convs.type && convs.type === "bigquery") {
    if (convs.data && convs.data.length > 0) {
      await Promise.all(
        convs.data.map(async (conv) => {
          let client = conv.cliente.split(" ");
          convsCerradas.push({
            fechaIni: new Date(conv.fecha_ini.value),
            fechaFin: conv.fecha_fin
              ? new Date(conv.fecha_fin.value)
              : new Date(conv.fecha_abandono?.value),
            fechaAbandono: conv.fecha_abandono
              ? new Date(conv.fecha_abandono.value)
              : false,
            fecha_asignacion: conv.fecha_asignacion
              ? new Date(conv.fecha_asignacion.value)
              : false,
            fecha_aceptacion: conv.fecha_aceptacion
              ? new Date(conv.fecha_aceptacion.value)
              : false,
            fecha_ini: new Date(conv.fecha_ini.value),
            agente: {
              nombres: emptyObject(conv.agente_nombre),
              mail: emptyObject(conv.agente_email),
              nickname: emptyObject(conv.agente_nickname),
            },
            asunto: conv.asunto,
            canal: conv.canal,
            cliente: {
              mail: emptyObject(client[client.length - 1]),
              nombre: client[0],
            },
            resuelta: conv.resuelta,
            encuesta: conv.encuesta ? conv.encuesta : false,
            tema: conv.tema ? conv.tema : false,
            idConv: conv.idConv,
            aceptaTerminos: emptyObject(conv.aceptaTerminos),
            suscribeContactar: emptyObject(conv.suscribeContactar),
          });
        })
      );
    }
  } else if (convs !== undefined) {
    if (convs.length > 0) {
      await Promise.all(
        convs.map(async (doc) => {
          let conv = doc.data();
          if (!conv.fecha_fin) {
            console.log("conv", conv);
          }
          convsCerradas.push({
            fechaIni: conv.fecha_ini.toDate(),
            fechaFin: conv.fecha_fin
              ? conv.fecha_fin.toDate()
              : conv.fecha_abandono.toDate(),
            fechaAbandono: conv.fecha_abandono
              ? conv.fecha_abandono.toDate()
              : false,
            fecha_asignacion: conv.fecha_asignacion
              ? conv.fecha_asignacion.toDate()
              : false,
            fecha_aceptacion: conv.fecha_aceptacion
              ? conv.fecha_aceptacion.toDate()
              : false,
            fecha_ini: conv.fecha_ini,
            agente: conv.agente,
            asunto: conv.asunto,
            canal: conv.canal,
            cliente: conv.cliente,
            resuelta: conv.resuelta,
            encuesta: conv.encuesta ? conv.encuesta : false,
            tema: conv.tema ? conv.tema : false,
            idConv: doc.id,
            aceptaTerminos: emptyObject(conv.aceptaTerminos),
            suscribeContactar: emptyObject(conv.suscribeContactar),
          });
        })
      );
    } else {
      if (convs && convs.fechaIni)
        convsCerradas.push({
          fechaIni: convs.fecha_ini.toDate(),
          fechaFin: convs.fecha_fin
            ? convs.fecha_fin.toDate()
            : convs.fecha_abandono.toDate(),
          fechaAbandono: convs.fecha_abandono
            ? convs.fecha_abandono.toDate()
            : false,
          fecha_asignacion: convs.fecha_asignacion
            ? convs.fecha_asignacion.toDate()
            : false,
          fecha_aceptacion: convs.fecha_aceptacion
            ? convs.fecha_aceptacion.toDate()
            : false,
          fecha_ini: convs.fecha_ini,
          agente: convs.agente,
          asunto: convs.asunto,
          canal: convs.canal,
          cliente: convs.cliente,
          resuelta: convs.resuelta,
          encuesta: convs.encuesta ? convs.encuesta : false,
          tema: convs.tema ? convs.tema : false,
          idConv: idConversacion,
          aceptaTerminos: emptyObject(convs.aceptaTerminos),
          suscribeContactar: emptyObject(convs.suscribeContactar),
        });
    }
  }

  return convsCerradas;
}

