function* obtenerDataNotasOcultas(action) {
  yield put(manageSpiner({ key: "notasOcultas", state: true }));
  let rango = obtenerRangoDeFechas(action.value);
  const timeIni = new Date(rango.fechaIni);
  const timeFin = new Date(rango.fechaFin);

  let convsCerradas = [];
  let reference = false;
  let reference2 = false;
  try {
    const company = getFromSession("company_id");

    reference2 = yield firebaseDatabase
      .collectionGroup(`notasOcultas`)
      .where("company", "==", `${company}`)
      .where("fecha", ">", timeIni)
      .where("fecha", "<", timeFin)
      .orderBy("fecha", "desc")
      .get();

    const respuesta2 = [];
    var dataSavedNotas = [];
    yield reference2.docs.map((doc, i) => {
      respuesta2.push({
        data: doc.data(),
        docPadre: doc._delegate._key.path.segments[8],
      });
    });

    if (respuesta2.length > 0) {
      dataSavedNotas = yield select(getDataNotasOcultas);
      var idConsulta = [];
      var respuesta = [];
      if (dataSavedNotas.length > 0) {
        idConsulta = yield getIdConsultas({
          dataLocal: dataSavedNotas,
          dataConsultas: respuesta2,
        });
        if (idConsulta.length > 0) {
          for (var element of idConsulta) {
            reference = yield firebaseDatabase
              .collection(`company/${company}/conversations`)
              .doc(element.docPadre)
              .get();
            respuesta.push({
              data: element.data,
              docPadre: element.docPadre,
              conversations: reference.data(),
            });
          }
          respuesta.forEach((element) => {
            dataSavedNotas.push(element);
          });
        }
      } else {
        for (var element of respuesta2) {
          reference = yield firebaseDatabase
            .collection(`company/${company}/conversations`)
            .doc(element.docPadre)
            .get();
          dataSavedNotas.push({
            data: element.data,
            docPadre: element.docPadre,
            docTrans: element.docTrans,
            conversations: reference.data(),
          });
        }
      }
      yield put(saveDataNotasOcultas(dataSavedNotas));
    }

    const data = yield crearDataTable({
      data: dataSavedNotas,
      coleccion: "notasocultas",
    });
    yield put(
      obtenerDataNotasOcultasSuccess({ data, columnsTable: HEADER_TABLE_NOTAS })
    );
    yield put(manageSpiner({ key: "notasOcultas", state: false }));
  } catch (error) {
    console.error("saga.obtenerDataNotasOcultas", error);
    yield put(obtenerConvsCerradasError(error));
  }
}

function convertirFecha(fecha) {
  const fech = fecha.toDate();
  return `${fech.getDate().toString()}/${(
    fech.getMonth() + 1
  ).toString()}/${fech.getFullYear().toString()} 
    ${fech.getHours().toString()}:${fech.getMinutes().toString()}:${fech
    .getSeconds()
    .toString()}`;
}

