function crearString(action) {
  const hour = Math.trunc(action / (1000 * 60 * 60));
  const min = Math.trunc(action / (1000 * 60));
  return `${hour.toString()}:${Math.trunc(
    (action - 1000 * 60 * 60 * hour) / (1000 * 60)
  ).toString()}:${Math.trunc(
    (action - 1000 * 60 * min) / 1000
  ).toString()}:${Math.trunc(
    (action / 1000 - Math.trunc(action / 1000)) * 1000
  ).toString()}`;
}

