function* crearLabelChart(action) {
  const { rango } = action;
  const timeIni = new Date(rango.fechaIni);
  const timeFin = new Date(rango.fechaFin);

  let fechaInicial = moment(timeIni);
  let fechaFinal = moment(timeFin);
  let diferenciaDias = fechaFinal.diff(fechaInicial, "days");
  const tipo = [];
  var banTipo = true;
  if (diferenciaDias > 0) {
    //rango fechas
    var aux = new Date(rango.fechaIni);
    var ban = true;
    while (ban) {
      const temp = `${aux.getDate().toString()}/${(
        aux.getMonth() + 1
      ).toString()}/${aux.getFullYear().toString()}`;

      if (
        aux.getFullYear() === timeFin.getFullYear() &&
        aux.getMonth() === timeFin.getMonth() &&
        aux.getDate() === timeFin.getDate()
      ) {
        ban = false;
      }
      tipo.push(temp);

      aux.setDate(aux.getDate() + 1);
    }
  } else {
    banTipo = false;
    // rango horas
    var cont = 0;
    while (cont < 25) {
      tipo.push(`${cont.toString()}:00`);
      cont += 1;
    }
  }
  return { tipo, banTipo };
}

