function* obtenerCanalesPorCompany(company) {
  try {
    const docRef = firebaseDatabase.doc(
      `company/${company}/configuration/NUM_CANALES_CONV`
    );
    const snapshot = yield docRef.get();

    if (!snapshot.exists) {
      console.warn(
        `No existe el documento NUM_CANALES_CONV para la compañía: ${company}`
      );
      return [];
    }

    const data = snapshot.data();
    let numCanales = [];

    // Caso 1: Estructura antigua → { value: ["web", "whatsapp"] }
    if (Array.isArray(data.value)) {
      numCanales = data.value;
    }

    // Caso 2: Estructura nueva → { value: { canalesHabilitados: ["web", "whatsapp"] } }
    else if (data.value && Array.isArray(data.value.canalesHabilitados)) {
      numCanales = data.value.canalesHabilitados;
    }

    // Si no es un array, devuelve vacío
    if (!Array.isArray(numCanales)) {
      console.warn("Formato de canales no válido, devolviendo array vacío");
      numCanales = [];
    }

    console.log("✅ Canales obtenidos:", numCanales);
    return numCanales;
  } catch (error) {
    console.error("❌ Error al obtener canales:", error);
    return [];
  }
}

