function* listarUsuariosConectados() {
  const currentUser = getFromSession("currentUser");
  const company = getFromSession("company_id");
  const uidCurrentUser = currentUser.uid;
  try {
    let usuarios = yield usuariosConectados();
    let usuariosDisplay = [];
    let posicion;
    let listaDisplay;
    let flag = false;
    let usuData = [];
    if (usuarios) {
      usuarios.forEach((usu) => {
        usuData.push(usu.data());
      });
      for (let usu of usuData) {
        let usuarioIdRef = usu.agente.idDoc;
        let convsAsignadas = yield contarConvsPorAgente(company, usuarioIdRef);
        const usuarioInfo = {
          habilidad: usu.agente.skill.nombre,
          nombres: usu.agente.nombres + " " + usu.agente.apellidos,
          convsActuales: convsAsignadas,
          usuario: usu,
        };
        usuariosDisplay.push(usuarioInfo);
      }
    }
    if (currentUser.rol === "SUPERVISOR" || currentUser.estado === 3) {
      listaDisplay = usuariosDisplay;
    } else {
      for (let i = 0; i < usuariosDisplay.length; i++) {
        if (usuariosDisplay[i].usuario.agente.uid === uidCurrentUser) {
          posicion = i;
          flag = true;
          break;
        }
      }
      if (flag) {
        listaDisplay = [...usuariosDisplay];
        listaDisplay.splice(posicion, 1);
      }
    }
    yield put(
      listarUsuariosConectadosSuccess({
        usuariosDisplay: listaDisplay,
        usuariosConectados: usuarios,
        verPanelTransfer: true,
      })
    );
  } catch (error) {
    console.error("agentPanel.saga.listarUsuariosConectados", error);
    put(generalError(error));
  }
}

function performOperationWithRetry(fileReference, archivo, catalogo) {
  const maxRetryAttempts = 3; // Puedes subirlo si quieres
  const retryDelay = 60000; // 1 minuto entre intentos

  let retryCount = 0;
  console.log("📂 Subiendo a ruta Firebase:", fileReference.fullPath);
  return new Promise((resolve, reject) => {
    const intentarSubida = () => {
      console.log(`Intentando subir archivo (intento ${retryCount + 1})...`);
      const uploadTask = fileReference.put(archivo);

      uploadTask.on(
        "state_changed",
        (snapshot) => {
          // Puedes agregar un log de progreso
          // console.log(`Progreso: ${(snapshot.bytesTransferred / snapshot.totalBytes) * 100}%`);
        },
        async (error) => {
          console.error("❌ Error detallado en subida Firebase:");
          console.error("Código:", error.code);
          console.error("Mensaje:", error.message);
          console.error("Stack:", error.stack);

          if (retryCount < maxRetryAttempts) {
            retryCount++;
            console.log(`🔁 Reintentando en ${retryDelay / 1000} segundos...`);
            setTimeout(intentarSubida, retryDelay);
          } else {
            reject(`Fallo tras ${maxRetryAttempts} intentos: ${error.message}`);
          }
        },
        () => {
          console.log("✅ Archivo subido correctamente");
          resolve("operacion terminada");
        }
      );
    };

    intentarSubida();
  });
}

