async function armarJSONparametros(
  company,
  idConversation,
  conversation,
  archivos,
  timestampDate
) {
  //Creamos una función asincrona cuyas tareas asincronas las vamos a sincronizar
  try {
    let parametros = [];
    for (const archivo of archivos) {
      const ref = `${company}/conversations/${idConversation}/${timestampDate}_${archivo.name}`;
      // const storageRef = storage.ref(ref);
      let typeArchivo = archivo.type;
      let tipo = typeArchivo.split(["/"])[0];
      let diccionarioTiposArchivo = {
        application: "file",
        image: "image",
        audio: "audio",
        video: "video",
      };
      let tipoArchivo = diccionarioTiposArchivo[tipo];
      tipoArchivo = !tipoArchivo ? "file" : tipoArchivo;
      //primera tarea asincrona, usamos await para esperar a que se resuelva la promesa
      const fireStorageRef = firebaseStorage.ref();
      const fileReference = fireStorageRef.child(ref);
      console.log("fileReference", archivo, ref);
      await performOperationWithRetry(fileReference, archivo, null)
        .then((result) => {
          console.log("Operación exitosa:", result);
          
          parametros.push({
            idConversation: idConversation,
            conversation: conversation,
            tipo: tipoArchivo,
            nombre: archivo.name,
            url:`https://storage.googleapis.com/${process.env.REACT_APP_FIREBASE_STORAGE_BUCKET}/${ref}`
              
          });
        })
        .catch((error) => {
          console.error("Operación fallida:", error);
          throw error;
        });
    }
    return parametros;
  } catch (error) {
    console.error("saga.js-armarJSONparametros", error);
  }
}

